                 var url = $"https://lite.duckduckgo.com/lite/?q={encoded}";
                 var html = await httpClient.GetStringAsync(url);

                 // Extract text snippets from the lite HTML results
                 var text = Regex.Replace(html, "<[^>]+>", " ");
                 text = Regex.Replace(text, @"\s+", " ").Trim();

                 // Return a meaningful window of results
                 const int maxLen = 3000;
                 if (text.Length > maxLen)
                     text = text[..maxLen] + "...";

                 return text;
             }
             catch (Exception ex)
             {
                 return $"Search failed: {ex.Message}";
             }
         },
         "web_search",
         "Search the web for information on a topic. Returns text snippets from search results."),

     AIFunctionFactory.Create(
         ([Description("A short key or title for the note")] string key,
          [Description("The content of the note")] string content) =>
         {
             notebook[key] = content;
             Console.WriteLine($"  📝 Note saved: \"{key}\"");
             return $"Note '{key}' saved successfully.";
         },
         "save_note",
         "Save a research note. Use this to record key findings as you research."),

     AIFunctionFactory.Create(
         () =>
         {
             if (notebook.IsEmpty)
                 return "No notes saved yet.";

             var sb = new StringBuilder();
             foreach (var (key, value) in notebook)
                 sb.AppendLine($"## {key}\n{value}\n");
             return sb.ToString();
         },
         "get_all_notes",
         "Retrieve all saved research notes.")
 };

 // --- Chat client setup (MEAI abstraction over OpenAI) ----------------------
 IChatClient innerClient = new OpenAIClient(apiKey)
     .GetChatClient(modelId)
     .AsIChatClient();

 // Wrap with automatic function invocation
 using var chatClient = new FunctionInvokingChatClient(innerClient);

 // --- Agent setup (Microsoft Agent Framework) -------------------------------
 var agent = new ChatClientAgent(
     chatClient: chatClient,
     instructions: """
         You are a thorough research assistant. Given a topic, you will:
         1. Search the web multiple times with varied queries to gather broad information.
         2. Save key findings as notes using the save_note tool.
         3. After gathering enough information (at least 3-4 searches), retrieve all
            notes and produce a comprehensive summary.

         Always search before answering. Vary your search queries to cover different
         angles of the topic. Save important facts as you go.
         End with a well-structured summary that synthesizes your findings.
         """,
     name: "ResearchAgent",
     description: "An agent that researches topics by searching the web and taking notes",
     tools: tools,
     loggerFactory: null,
     services: null);

 var chatOptions = new ChatOptions
 {
     Temperature = 0.2f,
     MaxOutputTokens = 2048,
     Tools = tools,
 };

 var session = await agent.CreateSessionAsync(CancellationToken.None);

 var runOptions = new ChatClientAgentRunOptions(chatOptions);

 // --- Run the agent ---------------------------------------------------------
 Console.WriteLine("─── Agent working... ───\n");

 var response = await agent.RunAsync(
     $"Research the following topic and provide a comprehensive summary: {topic}",
     session,
     runOptions,
     CancellationToken.None);

 // --- Display results -------------------------------------------------------
 Console.WriteLine("\n─── Research Summary ───\n");

 foreach (var message in response.Messages)
 {
     if (message.Role == ChatRole.Assistant && !string.IsNullOrWhiteSpace(message.Text))
     {
         Console.WriteLine(message.Text);
     }
 }

 if (!notebook.IsEmpty)
 {
     Console.WriteLine("\n─── Research Notes ───\n");
     foreach (var (key, value) in notebook)
     {
         Console.WriteLine($"📌 {key}");
         Console.WriteLine($"   {value}\n");
     }
 }

